    def _contains_malicious_patterns(self, script: str) -> bool:
        """
        Basic security check for malicious patterns
        """
        malicious_patterns = [
            "import ", "require ", "exec(", "eval(", "system(", 
            "__", "javascript:", "function", "new ", "this."
        ]
        
        script_lower = script.lower()
        for pattern in malicious_patterns:
            if pattern in script_lower:
                return True
        return False
    
